const BATHROOM_DETAIL_ROUTE_PATTERN = /^\/bathroom\/[^/]+$/;

type SafeRouter = Pick<Router, 'push' | 'replace'>;

export function isAppRoute(route: string): route is Href {
  return STATIC_ROUTES.has(route) || BATHROOM_DETAIL_ROUTE_PATTERN.test(route);
}

export function toSafeRoute(route: string | null | undefined, fallbackRoute: Href): Href {
  if (route && isAppRoute(route)) {
    return route;
  }

  return fallbackRoute;
}

export function routeFromSegments(segments: string[], fallbackRoute: Href): Href {
  if (!segments.length) {
    return fallbackRoute;
  }

  return toSafeRoute(`/${segments.join('/')}`, fallbackRoute);
}

export function pushSafely(router: SafeRouter, route: string | null | undefined, fallbackRoute: Href): void {
  router.push(toSafeRoute(route, fallbackRoute));
}

export function replaceSafely(router: SafeRouter, route: string | null | undefined, fallbackRoute: Href): void {
  router.replace(toSafeRoute(route, fallbackRoute));
}

